def palindrome_pairs(strings):
    n = len(strings)
    result = []
    for i in range(n):
        for j in range(n):
            if i != j:
                if is_palindrome(strings[i] + strings[j]):
                    result.append((i, j))
    return result

def is_palindrome(s):
    return s == s[::-1]
